    public void handlePositions(Client client, Object message)
    {
        //
        //    {
        //        feed: 'open_positions',
        //        account: '3b111acc-4fcc-45be-a622-57e611fe9f7f',
        //        positions: [
        //            {
        //                instrument: 'PF_LTCUSD',
        //                balance: 0.5,
        //                pnl: -0.8628305877699987,
        //                entry_price: 70.53,
        //                mark_price: 68.80433882446,
        //                index_price: 68.8091,
        //                liquidation_threshold: 0,
        //                effective_leverage: 0.007028866753648637,
        //                return_on_equity: -1.2233525985679834,
        //                unrealized_funding: 0.0000690610530935388,
        //                initial_margin: 0.7053,
        //                initial_margin_with_orders: 0.7053,
        //                maintenance_margin: 0.35265,
        //                pnl_currency: 'USD'
        //            }
        //        ],
        //        seq: 0,
        //        timestamp: 1698608414910
        //    }
        //
        if (Helpers.isTrue(Helpers.isEqual(this.positions, null)))
        {
            this.positions = new ArrayCache.ArrayCacheBySymbolById();
        }
        Object cache = this.positions;
        Object rawPositions = this.safeValue(message, "positions", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object newPositions = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawPositions)); i++)
        {
            Object rawPosition = Helpers.GetValue(rawPositions, i);
            Object position = this.parseWsPosition(rawPosition);
            Object timestamp = this.safeInteger(message, "timestamp");
            Helpers.addElementToObject(position, "timestamp", timestamp);
            Helpers.addElementToObject(position, "datetime", this.iso8601(timestamp));
            ((java.util.List<Object>)newPositions).add(position);
            Helpers.callDynamically(cache, "append", new Object[]{position});
        }
        Object messageHashes = this.findMessageHashes(client, "positions::");
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(messageHashes)); i++)
        {
            Object messageHash = Helpers.GetValue(messageHashes, i);
            Object parts = Helpers.split(messageHash, "::");
            Object symbolsString = Helpers.GetValue(parts, 1);
            Object symbols = Helpers.split(symbolsString, ",");
            Object positions = this.filterByArray(newPositions, "symbol", symbols, false);
            if (!Helpers.isTrue(this.isEmpty(positions)))
            {
                client.resolve(positions, messageHash);
            }
        }
        client.resolve(newPositions, "positions");
    }

    public Object parseWsPosition(Object position, Object... optionalArgs)
    {
        //
        //        {
        //            instrument: 'PF_LTCUSD',
        //            balance: 0.5,
        //            pnl: -0.8628305877699987,
        //            entry_price: 70.53,
        //            mark_price: 68.80433882446,
        //            index_price: 68.8091,
        //            liquidation_threshold: 0,
        //            effective_leverage: 0.007028866753648637,
        //            return_on_equity: -1.2233525985679834,
        //            unrealized_funding: 0.0000690610530935388,
        //            initial_margin: 0.7053,
        //            initial_margin_with_orders: 0.7053,
        //            maintenance_margin: 0.35265,
        //            pnl_currency: 'USD'
        //        }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(position, "instrument");
        Object hedged = "both";
        Object balanceString = this.safeString(position, "balance");
        Object side = null;
        if (Helpers.isTrue(Precise.stringGt(balanceString, "0")))
        {
            side = "long";
        } else if (Helpers.isTrue(Precise.stringLt(balanceString, "0")))
        {
            side = "short";
        }
        final Object finalSide = side;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", null );
            put( "symbol", KrakenfuturesCore.this.safeSymbol(marketId) );
            put( "notional", null );
            put( "marginMode", null );
            put( "liquidationPrice", KrakenfuturesCore.this.safeNumber(position, "liquidation_threshold") );
            put( "entryPrice", KrakenfuturesCore.this.safeNumber(position, "entry_price") );
            put( "unrealizedPnl", KrakenfuturesCore.this.safeNumber(position, "pnl") );
            put( "percentage", KrakenfuturesCore.this.safeNumber(position, "return_on_equity") );
            put( "contracts", KrakenfuturesCore.this.parseNumber(Precise.stringAbs(balanceString)) );
            put( "contractSize", null );
            put( "markPrice", KrakenfuturesCore.this.safeNumber(position, "mark_price") );
            put( "side", finalSide );
            put( "hedged", hedged );
            put( "timestamp", null );
            put( "datetime", null );
            put( "maintenanceMargin", KrakenfuturesCore.this.safeNumber(position, "maintenance_margin") );
            put( "maintenanceMarginPercentage", null );
            put( "collateral", null );
            put( "initialMargin", KrakenfuturesCore.this.safeNumber(position, "initial_margin") );
            put( "initialMarginPercentage", null );
            put( "leverage", null );
            put( "marginRatio", null );
        }});
    }

